                                <div className="bg-slate-950/50 border border-slate-800/60 rounded-lg overflow-hidden">
                                  <div className="grid grid-cols-4 bg-slate-900/80 px-3 py-2 border-b border-slate-800/60">
                                      <span className="col-span-2 text-[9px] font-bold text-slate-500">Test</span>
                                      <span className="text-[9px] font-bold text-slate-500 text-right">Val</span>
                                      <span className="text-[9px] font-bold text-slate-500 text-right">Unit</span>
                                  </div>
                                  <div className="divide-y divide-slate-800/30">
                                      {gameState.labResults.map((lab, i) => (
                                          <div key={i} className={`grid grid-cols-4 px-3 py-1.5 ${lab.flag ? 'bg-red-900/10' : ''}`}>
                                              <span className="col-span-2 text-[10px] font-medium text-slate-300 flex items-center gap-2">
                                                 {lab.name}
                                                 {lab.flag && <span className="text-[8px] font-bold bg-red-500/20 text-red-400 px-1 rounded">{lab.flag}</span>}
                                              </span>
                                              <span className={`text-[10px] font-mono font-bold text-right ${lab.flag ? 'text-red-400' : 'text-emerald-400'}`}>{lab.value}</span>
                                              <span className="text-[9px] text-slate-500 text-right uppercase">{lab.unit}</span>
                                          </div>
                                      ))}
                                  </div>
                                </div>
                             </div>
                          )}

                          <div>
                            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-4 block">Discovered Evidence</span>
                            <div className="space-y-4">
                               {(!gameState.messages || gameState.messages.filter(m => m.imageUrl).length === 0) && (
                                 <p className="text-[10px] text-slate-700 italic text-center py-4">No imaging or EKG assets.</p>
                               )}
                               {(gameState.messages || []).filter(m => m.imageUrl).map((m, i) => (
                                 <div key={i} className="group relative rounded-xl overflow-hidden border border-slate-800 hover:border-emerald-500/50 transition-all cursor-zoom-in bg-black/40">
                                    <img src={m.imageUrl} className="w-full h-32 object-cover opacity-80 group-hover:opacity-100 transition-opacity grayscale-[0.3] group-hover:grayscale-0" alt="Asset" />
                                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex flex-col justify-end p-2">
                                       <span className="text-[9px] font-black text-white uppercase truncate">{m.content.substring(0, 30)}...</span>
                                       <span className="text-[8px] text-slate-400 font-mono">{new Date(m.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                    </div>
                                 </div>
                               ))}
                            </div>
                          </div>

                          <div className="pt-6 border-t border-slate-800">
                             <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-3 block">Simulation Objectives</span>
                             <div className="space-y-2">
                                {(gameState.learningPoints || []).map((p, i) => (
                                   <div key={i} className="flex gap-2 items-start p-2 rounded bg-slate-950/20 border border-slate-800/40">
                                      <div className="w-1 h-1 rounded-full bg-emerald-500 mt-1.5 shrink-0"></div>
                                      <span className="text-[10px] text-slate-400 font-medium leading-relaxed">{p}</span>
                                   </div>
                                ))}
                             </div>
                          </div>
                       </div>
                    </div>
                  )}
                  {!chartOpen && (
                    <button onClick={() => setChartOpen(true)} className="w-10 bg-slate-900 border-l border-slate-800 flex items-center justify-center hover:bg-slate-800 transition-colors">
                       <span className="rotate-90 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] whitespace-nowrap">Open Chart</span>
                    </button>
                  )}
              </div>
          </div>
        );
    }
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-slate-200 overflow-hidden relative">
      <header className="px-6 py-4 bg-slate-950 border-b border-slate-900 flex justify-between items-center z-50 shrink-0">
        <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-emerald-600 rounded-lg flex items-center justify-center font-black text-white shadow-xl shadow-emerald-900/20">M</div>
            <div>
              <h1 className="text-base font-black tracking-tight text-white leading-none">MediSim <span className="text-emerald-500">ER</span></h1>
              <span className="text-[9px] text-slate-600 font-black uppercase tracking-[0.3em] mt-1 block">Clinical AI Interface v3.2</span>
            </div>
        </div>
        <div className="flex items-center gap-6">
            <div className="hidden md:flex items-center gap-2 bg-slate-900 border border-slate-800 px-3 py-1.5 rounded-full">
               <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
               <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">System Nominal</span>
            </div>
            {gameState.stage !== 'upload' && (
                 <button onClick={startNewCase} className="px-5 py-2 rounded-full bg-slate-900 border border-slate-800 text-[10px] font-black uppercase tracking-[0.1em] text-slate-400 hover:text-white hover:bg-slate-800 transition-all">End Session</button>
            )}
        </div>
      </header>
      {renderContent()}
      {error && <ErrorModal message={error} onDismiss={() => setError(null)} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { GameState, Message } from './types';
import { analyzePDFAndStartCase, progressSimulation, GeminiFileInput } from './services/geminiService';
import { extractImagesFromPDF } from './services/pdfService';
import VitalsMonitor from './components/VitalsMonitor';
import ChatInterface from './components/ChatInterface';
import Controls from './components/Controls';
import DebriefScreen from './components/DebriefScreen';
import ErrorModal from './components/ErrorModal';
import { playDefibrillationSequence, startAmbientNoise, stopAmbientNoise } from './services/audioEffectsService';

const SAVE_KEY = 'medisim_er_save_state';
const API_KEY_STORAGE = 'medisim_er_api_key';
const CLIENT_ID_STORAGE = 'medisim_google_client_id';

const getEnvKey = () => {
  try {
    return (typeof process !== 'undefined' && process.env) ? process.env.API_KEY || '' : '';
  } catch (e) {
    return '';
  }
};

const fileToBase64 = (file: File | Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

const DEFAULT_STATE: GameState = {
  stage: 'upload',
  vitals: { hr: 0, bpSystolic: 0, bpDiastolic: 0, rr: 0, o2: 0, temp: 0, rhythm: '--' },
  messages: [],
  learningPoints: [],
  hiddenDiagnosis: '',
  caseContext: '',
  visuals: [],
  labResults: [],
  diagnosticReports: [],
  vitalTrend: 'stable'
};

const App: React.FC = () => {
  const [apiKey, setApiKey] = useState<string>(() => {
    return localStorage.getItem(API_KEY_STORAGE) || getEnvKey();
  });

  const [clientId, setClientId] = useState<string>(() => {
    return localStorage.getItem(CLIENT_ID_STORAGE) || '';
  });

  const [gameState, setGameState] = useState<GameState>(() => {
    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed && ['upload', 'analyzing', 'playing', 'debrief'].includes(parsed.stage)) {
          // Merge with DEFAULT_STATE to ensure all array properties exist
          return { ...DEFAULT_STATE, ...parsed };
        }
      } catch (e) {
        console.error("Failed to recover saved state:", e);
      }
    }
    return DEFAULT_STATE;
  });

  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [timer, setTimer] = useState(0);
  const [audioMonitor, setAudioMonitor] = useState(false);
  const [chartOpen, setChartOpen] = useState(true);
  const [driveConfigOpen, setDriveConfigOpen] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);

  const getAudioContext = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: 24000
      });
    }
    return audioContextRef.current;
  };

  // Manage ambient noise
  useEffect(() => {
    if (gameState.stage === 'playing' && audioMonitor) {
       const ctx = getAudioContext();
       if (ctx.state === 'suspended') ctx.resume();
       startAmbientNoise(ctx);
    } else {
       stopAmbientNoise();
    }
    return () => stopAmbientNoise();
  }, [gameState.stage, audioMonitor]);

  useEffect(() => {
    let interval: any;
    if (gameState.stage === 'playing') {
      interval = setInterval(() => setTimer(t => t + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [gameState.stage]);

  useEffect(() => {
    if (gameState.stage !== 'upload') {
      localStorage.setItem(SAVE_KEY, JSON.stringify(gameState));
    }
  }, [gameState]);

  useEffect(() => {
    if (apiKey) {
      localStorage.setItem(API_KEY_STORAGE, apiKey);
    }
  }, [apiKey]);

  useEffect(() => {
    if (clientId) {
      localStorage.setItem(CLIENT_ID_STORAGE, clientId);
    }
  }, [clientId]);

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleOpenSelectKey = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
      const updatedKey = getEnvKey();
      if (updatedKey) setApiKey(updatedKey);
    } else {
      window.open('https://aistudio.google.com/app/apikey', '_blank');
    }
  };

  const startNewCase = () => {
    localStorage.removeItem(SAVE_KEY);
    setGameState(DEFAULT_STATE);
    setSelectedFiles([]);
    setTimer(0);
  };

  const processFiles = async (files: File[]) => {
    const currentKey = apiKey || getEnvKey();
    if (!currentKey) {
      setError("Please enter or select your Google Gemini API Key.");
      return;
    }

    if (files.length === 0) return;

    setIsLoading(true);
    setError(null);
    setGameState(prev => ({ ...prev, stage: 'analyzing' }));

    try {
      setLoadingStep('Initializing Neural Engine...');
      const geminiInputs: GeminiFileInput[] = [];
      const allVisualAssets: string[] = [];

      for (const file of files) {
        setLoadingStep(`Analyzing ${file.name}...`);
        const base64Data = await fileToBase64(file);
        geminiInputs.push({ mimeType: file.type, data: base64Data });

        if (file.type === 'application/pdf') {
          const buffer = await file.arrayBuffer();
          const extractedImages = await extractImagesFromPDF(buffer);
          allVisualAssets.push(...extractedImages);
        } else if (file.type.startsWith('image/')) {
          allVisualAssets.push(`data:${file.type};base64,${base64Data}`);
        }
      }

      setLoadingStep('Constructing clinical logic...');
      const initData = await analyzePDFAndStartCase(currentKey, geminiInputs, allVisualAssets);

      setGameState(prev => ({
        ...prev,
        stage: 'playing',
        vitals: initData.vitals,
        messages: [{
          role: 'assistant',
          content: initData.intro,
          timestamp: Date.now()
        }],
        learningPoints: initData.learningPoints || [],
        hiddenDiagnosis: initData.diagnosis,
        caseContext: initData.context,
        visuals: initData.visualCatalog || [],
        labResults: [],
        diagnosticReports: [],
        vitalTrend: 'stable'
      }));
    } catch (err: any) {
      console.error("Error setting up case:", err);
      if (err.message?.includes("Requested entity was not found")) {
        setError("API Key verification failed. Please re-select your key.");
      } else {
        setError(`Setup Error: ${err.message || "Unknown error"}. Ensure Key is valid.`);
      }
      setGameState(prev => ({ ...prev, stage: 'upload' }));
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(event.target.files || []) as File[];
    const validTypes = ['application/pdf', 'image/png', 'image/jpeg', 'image/jpg'];
    const invalidFile = files.find(f => !validTypes.includes(f.type));

    if (invalidFile) {
      setError(`Invalid file: ${invalidFile.name}. Use PDF or Images.`);
      return;
    }
    setSelectedFiles(prev => [...(prev || []), ...files]);
    event.target.value = ''; 
  };

  // Google Drive Picker Implementation
  const handleDrivePicker = () => {
    if (!clientId) {
        setError("Please configure your Google Cloud Client ID for Drive access.");
        setDriveConfigOpen(true);
        return;
    }

    const gapi = (window as any).gapi;
    const google = (window as any).google;

    if (!gapi || !google) {
        setError("Google API scripts failed to load. Please check your internet connection.");
        return;
    }

    const loadPicker = () => {
        const tokenClient = google.accounts.oauth2.initTokenClient({
            client_id: clientId,
            scope: 'https://www.googleapis.com/auth/drive.readonly',
            callback: async (response: any) => {
                if (response.error !== undefined) {
                    setError(`Auth Error: ${response.error}`);
                    return;
                }
                createPicker(response.access_token);
            },
        });
        tokenClient.requestAccessToken({ prompt: '' });
    };

    const createPicker = (accessToken: string) => {
        const view = new google.picker.View(google.picker.ViewId.DOCS);
        view.setMimeTypes('application/pdf,image/png,image/jpeg,image/jpg');

        const picker = new google.picker.PickerBuilder()
            .addView(view)
            .setOAuthToken(accessToken)
            .setDeveloperKey(apiKey || getEnvKey()) // Reuse Gemini Key as Dev Key (User needs Drive API enabled)
            .setCallback((data: any) => pickerCallback(data, accessToken))
            .build();
        picker.setVisible(true);
    };

    const pickerCallback = async (data: any, accessToken: string) => {
        if (data.action === google.picker.Action.PICKED) {
            setIsLoading(true);
            setLoadingStep('Downloading files from Drive...');

            try {
                const newFiles: File[] = [];
                for (const doc of data.docs) {
                    const fileId = doc.id;
                    const mimeType = doc.mimeType;
                    const name = doc.name;

                    // Fetch file content using the access token
                    const response = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
                        headers: { Authorization: `Bearer ${accessToken}` }
                    });

                    if (!response.ok) throw new Error(`Failed to download ${name}`);

                    const blob = await response.blob();
                    const file = new File([blob], name, { type: mimeType });
                    newFiles.push(file);
                }

                setSelectedFiles(prev => [...(prev || []), ...newFiles]);
                setIsLoading(false);
            } catch (err: any) {
                console.error("Drive Download Error", err);
                setError("Failed to download files from Google Drive.");
                setIsLoading(false);
            }
        }
    };

    gapi.load('picker', { callback: loadPicker });
  };

  const handleUserAction = async (actionText: string) => {
    if (isLoading) return;

    const currentKey = apiKey || getEnvKey();
    if (!currentKey) {
      setError("API Key missing. Please configure your key.");
      return;
    }

    const lowerAction = actionText.toLowerCase();
    const isDefibAction = lowerAction.includes('defib') || lowerAction.includes('shock') || lowerAction.includes('cardioversion');

    const userMsg: Message = { role: 'user', content: actionText, timestamp: Date.now() };
    setGameState(prev => ({ ...prev, messages: [...(prev.messages || []), userMsg] }));

    if (isDefibAction) {
      const ctx = getAudioContext();
      if (ctx.state === 'suspended') await ctx.resume();
      playDefibrillationSequence(ctx);
    }

    setIsLoading(true);
    setError(null);

    try {
      const historyStrings = (gameState.messages || []).map(m => `${m.role.toUpperCase()}: ${m.content}`);
      const response = await progressSimulation(currentKey, gameState.caseContext, historyStrings, actionText, gameState.visuals || []);

      let imageUrl: string | undefined = undefined;
      if ((response as any)._generatedImageUrl) {
        imageUrl = (response as any)._generatedImageUrl;
      } else if (response.imageIdToDisplay) {
        const foundVisual = (gameState.visuals || []).find(v => v.id === response.imageIdToDisplay);
        if (foundVisual) imageUrl = foundVisual.data;
      }

      const sysMsg: Message = {
        role: 'assistant',
        content: response.narrative,
        timestamp: Date.now(),
        type: (response.updatedVitals.hr < 50 || response.updatedVitals.hr > 130 || response.updatedVitals.o2 < 92) ? 'alert' : 'text',
        imageUrl: imageUrl
      };

      if (response.isCaseOver && response.debriefData) {
        setGameState(prev => ({
          ...prev,
          vitals: response.updatedVitals,
          vitalTrend: response.vitalTrend || 'stable',
          messages: [...(prev.messages || []), sysMsg],
          debriefData: response.debriefData,
          stage: 'debrief'
        }));
      } else {
        setGameState(prev => {
          const newLabs = response.labResults || [];
          const combinedLabs = [...(prev.labResults || [])];
          newLabs.forEach(lab => combinedLabs.push(lab));

          // Process diagnostic reports
          const newReports = (response.diagnosticReports || []).map(r => ({
            ...r,
            timestamp: Date.now()
          }));
          const combinedReports = [
             ...newReports,
             ...(prev.diagnosticReports || [])
          ]; // Newest first

          return {
            ...prev,
            vitals: response.updatedVitals,
            vitalTrend: response.vitalTrend || 'stable',
            messages: [...(prev.messages || []), sysMsg],
            labResults: combinedLabs,
            diagnosticReports: combinedReports
          };
        });
      }
    } catch (err: any) {
      console.error("Simulation error:", err);
      setError(`Logic Error: ${err.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    switch (gameState.stage) {
      case 'upload':
      case 'analyzing':
        return (
          <div className="flex-1 overflow-y-auto bg-slate-900 flex flex-col items-center py-12 px-6 animate-fadeIn">
            <div className="max-w-2xl w-full bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-2xl backdrop-blur-xl text-center">
              <div className="mb-6 text-6xl drop-shadow-lg">🏥</div>
              <h2 className="text-3xl font-black text-white mb-2 tracking-tight">ER Simulation Hub</h2>
              <p className="text-slate-400 mb-8 max-w-sm mx-auto font-medium">Upload clinical guidelines or imaging to generate a dynamic, high-fidelity case.</p>

              {gameState.stage === 'analyzing' ? (
                   <div className="flex flex-col items-center gap-6 py-12">
                      <div className="relative">
                        <div className="w-20 h-20 border-4 border-emerald-500/10 rounded-full"></div>
                        <div className="absolute inset-0 w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                      </div>
                      <p className="text-emerald-400 font-mono text-sm font-black animate-pulse uppercase tracking-[0.2em]">{loadingStep}</p>
                   </div>
              ) : (
                  <div className="space-y-6">
                      <div className="text-left bg-slate-950/50 p-5 rounded-xl border border-slate-800/80">
                        <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 tracking-[0.2em]">Google Gemini API Key</label>
                        <div className="flex gap-2 mb-3">
                          <input
                            type="password"
                            value={apiKey}
                            onChange={(e) => setApiKey(e.target.value)}
                            placeholder="AIzaSy..."
                            className="flex-1 bg-slate-950 border border-slate-800 rounded-lg px-4 py-3 text-white font-mono text-sm focus:border-emerald-500 outline-none transition-all"
                          />
                          <button 
                            onClick={handleOpenSelectKey}
                            className="bg-slate-800 hover:bg-slate-700 text-emerald-500 border border-slate-700 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all"
                          >
                            Select Key
                          </button>
                        </div>

                        <div className="flex items-center gap-2">
                           <button onClick={() => setDriveConfigOpen(!driveConfigOpen)} className="text-[10px] text-slate-600 hover:text-emerald-500 font-bold uppercase tracking-widest flex items-center gap-1 transition-colors">
                             {driveConfigOpen ? 'Hide' : 'Show'} Google Drive Settings {driveConfigOpen ? '▲' : '▼'}
                           </button>
                        </div>

                        {driveConfigOpen && (
                          <div className="mt-3 pt-3 border-t border-slate-800/50 animate-fadeIn">
                             <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 tracking-[0.2em]">Google Cloud Client ID</label>
                             <input
                                type="text"
                                value={clientId}
                                onChange={(e) => setClientId(e.target.value)}
                                placeholder="123456789-abc...apps.googleusercontent.com"
                                className="w-full bg-slate-950 border border-slate-800 rounded-lg px-4 py-3 text-white font-mono text-xs focus:border-emerald-500 outline-none transition-all"
                             />
                             <div className="mt-3 bg-blue-900/10 border border-blue-900/30 rounded p-3">
                                <p className="text-[10px] font-bold text-blue-400 uppercase tracking-wider mb-2">Setup Instructions</p>
                                <ol className="list-decimal pl-4 text-[10px] text-slate-400 space-y-1 font-mono leading-relaxed">
                                   <li>Go to <a href="https://console.cloud.google.com" target="_blank" rel="noreferrer" className="text-emerald-500 hover:underline">Google Cloud Console</a> & create a project.</li>
                                   <li>Enable <strong>Google Drive API</strong> and <strong>Google Picker API</strong>.</li>
                                   <li>Go to <strong>Credentials</strong> → Create <strong>OAuth Client ID</strong>.</li>
                                   <li>Select 'Web application'. Add your URL (e.g., http://localhost:5173) to <strong>Authorized JavaScript origins</strong>.</li>
                                   <li>Copy the Client ID string above.</li>
                                </ol>
                             </div>
                          </div>
                        )}

                        <div className="flex justify-between mt-3 px-1 border-t border-slate-800/50 pt-2">
                          <p className="text-[10px] text-slate-600 font-bold uppercase tracking-wider">Required for Simulation Engine</p>
                          <a 
                            href="https://aistudio.google.com/app/apikey" 
                            target="_blank" 
                            rel="noreferrer" 
                            className="text-[10px] text-emerald-500 hover:text-emerald-400 font-black uppercase tracking-widest flex items-center gap-1 group"
                          >
                            Get Key 
                            <span className="group-hover:translate-x-1 transition-transform">&rarr;</span>
                          </a>
                        </div>
                      </div>

                      <div className="flex gap-4">
                        {/* Native File Input */}
                        <div className={`relative group flex-1 cursor-pointer`}>
                            <input type="file" accept="application/pdf,image/*" onChange={handleFileSelect} multiple className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" />
                            <div className="border-2 border-dashed border-slate-700 rounded-2xl p-8 group-hover:border-emerald-500 group-hover:bg-emerald-500/5 transition-all flex flex-col items-center gap-4 h-full justify-center">
                                <div className="w-12 h-12 rounded-full bg-slate-800 flex items-center justify-center group-hover:scale-110 transition-all shadow-xl">
