import { GoogleGenAI, Type } from "@google/genai";
import { Vitals, SimulationResponse, ExtractedImage } from "../types";

const getAI = (apiKey: string) => new GoogleGenAI({ apiKey });

// Using Flash models to ensure compatibility with free-tier API keys
const PRO_MODEL = "gemini-3-flash-preview"; 
const FLASH_MODEL = "gemini-3-flash-preview"; 

/**
 * Utility to robustly extract JSON from model responses that might contain markdown or conversational filler.
 */
function extractJson(text: string): string {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    return text.substring(start, end + 1);
  }
  return text.trim();
}

export interface GeminiFileInput {
  mimeType: string;
  data: string; // base64
}

export const analyzePDFAndStartCase = async (
  apiKey: string,
  files: GeminiFileInput[],
  extractedImages: string[]
): Promise<{ 
  intro: string; 
  vitals: Vitals; 
  context: string; 
  learningPoints: string[]; 
  diagnosis: string;
  visualCatalog: ExtractedImage[];
}> => {
  const ai = getAI(apiKey);

  const systemInstruction = `You are a Clinical Simulation Architect. 
  Your goal is to transform provided medical documents (PDFs, Images, EKGs, etc.) into a high-fidelity, difficult ER simulation. 

  CRITICAL RULES:
  1. NEVER reveal the diagnosis in the 'intro' or initial bedside report.
  2. The 'intro' MUST be a bedside scene with character dialogue.
  3. The 'rhythm' in vitals must be one of: "Sinus Rhythm", "Sinus Tachycardia", "Sinus Bradycardia", "Peaked T-Waves", "ST Elevation", "Atrial Fibrillation", "VT", "VF".
  4. NO SPOILERS: If the case involves Addison's, don't mention "low cortisol" or "adrenal" in the intro.
  5. OUTPUT VALID JSON ONLY. Escape all double quotes inside strings.`;

  const prompt = `
    Analyze the attached medical records (PDFs/Images). Create a simulation case.

    We have ${extractedImages.length} available visual assets (pages extracted from PDFs or uploaded images). Map them to clinical findings where appropriate.

    The 'intro' MUST be written as a scene:
    Nurse: "Doctor, glad you're here. This is Bed 4..."
    Patient: "(Weakly) I... I don't feel right..."

    OUTPUT FORMAT:
    {
      "intro": "Bedside dialogue...",
      "vitals": { "hr": 90, "bpSystolic": 120, "bpDiastolic": 80, "rr": 16, "o2": 98, "temp": 37.0, "rhythm": "Sinus Rhythm" },
      "context": "Secret clinical truth and image mapping.",
      "learningPoints": ["..."],
      "diagnosis": "The hidden diagnosis",
      "visualCatalog": [ { "id": "0", "label": "Initial EKG" } ]
    }
  `;

  const fileParts = files.map(f => ({
    inlineData: { mimeType: f.mimeType, data: f.data }
  }));

  try {
    const response = await ai.models.generateContent({
      model: PRO_MODEL,
      contents: {
        parts: [
          ...fileParts,
          { text: prompt },
        ],
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            intro: { type: Type.STRING },
            vitals: {
              type: Type.OBJECT,
              properties: {
                hr: { type: Type.NUMBER },
                bpSystolic: { type: Type.NUMBER },
                bpDiastolic: { type: Type.NUMBER },
                rr: { type: Type.NUMBER },
                o2: { type: Type.NUMBER },
                temp: { type: Type.NUMBER },
                rhythm: { type: Type.STRING },
              },
              required: ["hr", "bpSystolic", "bpDiastolic", "rr", "o2", "temp", "rhythm"],
            },
            context: { type: Type.STRING },
            learningPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
            diagnosis: { type: Type.STRING },
            visualCatalog: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  label: { type: Type.STRING },
                },
                required: ["id", "label"],
              }
            }
          },
        },
      },
    });

    const cleanText = extractJson(response.text);
    const result = JSON.parse(cleanText);

    const finalVisuals: ExtractedImage[] = (result.visualCatalog || []).map((item: any) => ({
      ...item,
      data: extractedImages[parseInt(item.id)] || ""
    })).filter((v: any) => v.data !== "");

    return { 
      ...result, 
      learningPoints: result.learningPoints || [],
      visualCatalog: finalVisuals 
    };
  } catch (error) {
    console.error("Error starting case:", error);
    throw error;
  }
};

export const progressSimulation = async (
  apiKey: string,
  context: string,
  history: string[],
  userAction: string,
  visuals: ExtractedImage[]
): Promise<SimulationResponse> => {
  const ai = getAI(apiKey);

  const systemInstruction = `You are the Bedside Simulation Engine. 

  STRICT RULES FOR NARRATIVE:
  1. USE FIRST-PERSON DIALOGUE.
  2. IMAGE DELIVERY: If the user asks for a test that is in VISUALS INVENTORY, return its ID. If NOT in inventory, describe it in narrative. DO NOT GENERATE IMAGES.
  3. LABS: If the user orders labs (CBC, BMP, Trop, etc.), return them in the 'labResults' array.
  4. DIAGNOSTIC REPORTS: If the user orders imaging (X-Ray, CT, US) or EKG/ECG, generate a formal report in 'diagnosticReports'.
  5. PHYSICAL EXAM: If the user requests physical exam findings (e.g. 'listen to lung sounds', 'examine abdomen', 'full exam'), you MUST return them in the 'physicalExam' array, not just in the narrative.
     - 'system': e.g., 'General', 'HEENT', 'CV', 'Lungs', 'Abd', 'Neuro', 'Skin', 'Ext'.
     - 'finding': The specific finding.
  6. PHYSIOLOGY: Determine the 'vitalTrend' based on the disease course and user actions.
  7. OUTPUT VALID JSON ONLY.`;

  const visualInventory = (visuals || []).map(v => `ID ${v.id}: ${v.label}`).join(", ");

  const prompt = `
    CLINICAL TRUTH: ${context}
    HISTORY: ${history.slice(-5).join("\n")}
    USER ACTION: ${userAction}
    VISUALS INVENTORY: ${visualInventory}

    Respond in JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: FLASH_MODEL,
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
         responseSchema: {
          type: Type.OBJECT,
          properties: {
            narrative: { type: Type.STRING },
            updatedVitals: {
              type: Type.OBJECT,
              properties: {
                hr: { type: Type.NUMBER },
                bpSystolic: { type: Type.NUMBER },
                bpDiastolic: { type: Type.NUMBER },
                rr: { type: Type.NUMBER },
                o2: { type: Type.NUMBER },
                temp: { type: Type.NUMBER },
                rhythm: { type: Type.STRING },
              },
              required: ["hr", "bpSystolic", "bpDiastolic", "rr", "o2", "temp", "rhythm"],
            },
            vitalTrend: { type: Type.STRING, enum: ["stable", "improving", "worsening", "critical"] },
            labResults: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  value: { type: Type.STRING },
                  unit: { type: Type.STRING },
                  flag: { type: Type.STRING, enum: ["H", "L", "CRITICAL"], nullable: true }
                }
              },
              nullable: true
            },
            diagnosticReports: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  body: { type: Type.STRING },
                }
              },
              nullable: true
            },
            physicalExam: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  system: { type: Type.STRING },
                  finding: { type: Type.STRING }
                }
              },
              nullable: true
            },
            isCaseOver: { type: Type.BOOLEAN },
            imageIdToDisplay: { type: Type.STRING, nullable: true },
            debriefData: {
                type: Type.OBJECT,
                properties: {
                    outcome: { type: Type.STRING },
                    score: { type: Type.INTEGER },
                    summary: { type: Type.STRING },
                    performanceBreakdown: {
                        type: Type.OBJECT,
                        properties: {
                            historyDataCollection: { type: Type.INTEGER },
                            differentialDiagnosis: { type: Type.INTEGER },
                            medicalManagement: { type: Type.INTEGER },
                            communicationEfficiency: { type: Type.INTEGER },
                        }
                    },
                    criticalEvents: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                event: { type: Type.STRING },
                                userAction: { type: Type.STRING },
                                optimalAction: { type: Type.STRING },
                                feedback: { type: Type.STRING },
                                type: { type: Type.STRING }
                            }
                        }
                    },
                    missedOpportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
                    cmeLearningPoints: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            }
          },
        },
      },
    });

    const cleanText = extractJson(response.text);
    const parsed = JSON.parse(cleanText);

    if (parsed.debriefData) {
      parsed.debriefData.criticalEvents = parsed.debriefData.criticalEvents || [];
      parsed.debriefData.missedOpportunities = parsed.debriefData.missedOpportunities || [];
      parsed.debriefData.cmeLearningPoints = parsed.debriefData.cmeLearningPoints || [];
    }

    // Default to stable if undefined
    if (!parsed.vitalTrend) parsed.vitalTrend = 'stable';

    return parsed;
  } catch (error) {
    console.error("Error progressing simulation:", error);
    throw error;
  }
};

