import { GoogleGenAI, Type } from "@google/genai";
import { Vitals, SimulationResponse, ExtractedImage } from "../types";

// Always use the latest process.env.API_KEY which is updated by the selection dialog
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY as string });

// Model constants
const ANALYSIS_MODEL = "gemini-3-pro-preview"; // High-fidelity analysis
const PROGRESSION_MODEL = "gemini-3-flash-preview"; // Low-latency interaction

function extractJson(text: string): string {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    return text.substring(start, end + 1);
  }
  return text.trim();
}

export interface GeminiFileInput {
  mimeType: string;
  data: string;
}

export const analyzePDFAndStartCase = async (
  files: GeminiFileInput[],
  extractedImages: string[]
): Promise<{ 
  intro: string; 
  vitals: Vitals; 
  context: string; 
  learningPoints: string[]; 
  diagnosis: string;
  visualCatalog: ExtractedImage[];
}> => {
  const ai = getAI();

  const systemInstruction = `You are a Clinical Simulation Architect. 
  Your goal is to transform medical documents into a high-fidelity ER simulation.

  RULES:
  1. NO SPOILERS: Never reveal the diagnosis or learning objectives in the intro.
  2. The 'intro' MUST be a bedside scene with character dialogue (Nurse/Patient).
  3. JSON OUTPUT ONLY.`;

  const prompt = `
    Analyze the attached medical records. Create a complex simulation case.
    Available visual assets: ${extractedImages.length}.

    OUTPUT FORMAT:
    {
      "intro": "Bedside dialogue...",
      "vitals": { "hr": 90, "bpSystolic": 120, "bpDiastolic": 80, "rr": 16, "o2": 98, "temp": 37.0, "rhythm": "Sinus Rhythm" },
      "context": "Secret clinical truth and logic mapping.",
      "learningPoints": ["..."],
      "diagnosis": "The hidden diagnosis",
      "visualCatalog": [ { "id": "0", "label": "Initial EKG" } ]
    }
  `;

  const fileParts = files.map(f => ({
    inlineData: { mimeType: f.mimeType, data: f.data }
  }));

  const response = await ai.models.generateContent({
    model: ANALYSIS_MODEL,
    contents: { parts: [...fileParts, { text: prompt }] },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
    },
  });

  const result = JSON.parse(extractJson(response.text));
  const finalVisuals: ExtractedImage[] = (result.visualCatalog || []).map((item: any) => ({
    ...item,
    data: extractedImages[parseInt(item.id)] || ""
  })).filter((v: any) => v.data !== "");

  return { ...result, visualCatalog: finalVisuals };
};

export const progressSimulation = async (
  context: string,
  history: string[],
  userAction: string,
  visuals: ExtractedImage[]
): Promise<SimulationResponse> => {
  const ai = getAI();

  const systemInstruction = `You are the Bedside Simulation Engine. 

  STRICT CHARTING RULES:
  1. PHYSICAL EXAM: Only return findings in 'physicalExam' if specifically requested.
  2. RADIOLOGY: If imaging is ordered, return a report in 'diagnosticReports'.
  3. LABS: Return structured values in 'labResults'.
  4. DO NOT reveal the hidden diagnosis in the narrative.
  5. Respond only in JSON.`;

  const visualInventory = (visuals || []).map(v => `ID ${v.id}: ${v.label}`).join(", ");
  const prompt = `CLINICAL TRUTH: ${context}\nHISTORY: ${history.slice(-5).join("\n")}\nUSER ACTION: ${userAction}\nVISUALS: ${visualInventory}`;

  const response = await ai.models.generateContent({
    model: PROGRESSION_MODEL,
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
    },
  });

  return JSON.parse(extractJson(response.text));
};

import React, { useState, useEffect, useRef } from 'react';
import { GameState, Message } from './types';
import { analyzePDFAndStartCase, progressSimulation, GeminiFileInput } from './services/geminiService';
import { extractImagesFromPDF } from './services/pdfService';
import VitalsMonitor from './components/VitalsMonitor';
import ChatInterface from './components/ChatInterface';
import Controls from './components/Controls';
import DebriefScreen from './components/DebriefScreen';
import ErrorModal from './components/ErrorModal';
import { playDefibrillationSequence, startAmbientNoise, stopAmbientNoise } from './services/audioEffectsService';

const SAVE_KEY = 'medisim_er_save_state';

const fileToBase64 = (file: File | Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
    reader.onerror = (error) => reject(error);
  });
};

const DEFAULT_STATE: GameState = {
  stage: 'upload',
  vitals: { hr: 0, bpSystolic: 0, bpDiastolic: 0, rr: 0, o2: 0, temp: 0, rhythm: '--' },
  messages: [],
  learningPoints: [],
  hiddenDiagnosis: '',
  caseContext: '',
  visuals: [],
  labResults: [],
  diagnosticReports: [],
  physicalExam: [],
  vitalTrend: 'stable'
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(() => {
    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try { return { ...DEFAULT_STATE, ...JSON.parse(saved) }; } catch (e) { return DEFAULT_STATE; }
    }
    return DEFAULT_STATE;
  });

  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [audioMonitor, setAudioMonitor] = useState(false);
  const [chartOpen, setChartOpen] = useState(true);
  const [hasKey, setHasKey] = useState(false);

  // Check if a key is already selected on mount
  useEffect(() => {
    const checkKey = async () => {
      if ((window as any).aistudio?.hasSelectedApiKey) {
        const selected = await (window as any).aistudio.hasSelectedApiKey();
        setHasKey(selected);
      } else {
        // Fallback for non-AI Studio environments
        setHasKey(true);
      }
    };
    checkKey();
  }, []);

  const handleOpenSelectKey = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
      setHasKey(true); // Assume success per instructions
    } else {
      setError("API Key selection is only available in the AI Studio environment.");
    }
  };

  useEffect(() => {
    if (gameState.stage === 'playing' && audioMonitor) {
       const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
       startAmbientNoise(ctx);
       return () => stopAmbientNoise();
    }
  }, [gameState.stage, audioMonitor]);

  useEffect(() => {
    if (gameState.stage !== 'upload') localStorage.setItem(SAVE_KEY, JSON.stringify(gameState));
  }, [gameState]);

  const processFiles = async (files: File[]) => {
    if (files.length === 0) return;
    if (!hasKey) {
      setError("Please select an API Key before starting the simulation.");
      return;
    }

    setIsLoading(true);
    setGameState(prev => ({ ...prev, stage: 'analyzing' }));

    try {
      setLoadingStep('Extracting medical data...');
      const geminiInputs: GeminiFileInput[] = [];
      const allVisualAssets: string[] = [];

      for (const file of files) {
        setLoadingStep(`Analyzing ${file.name}...`);
        const base64Data = await fileToBase64(file);
        geminiInputs.push({ mimeType: file.type, data: base64Data });
        if (file.type === 'application/pdf') {
          const extracted = await extractImagesFromPDF(await file.arrayBuffer());
          allVisualAssets.push(...extracted);
        } else {
          allVisualAssets.push(`data:${file.type};base64,${base64Data}`);
        }
      }

      setLoadingStep('Generating complex ER case...');
      const initData = await analyzePDFAndStartCase(geminiInputs, allVisualAssets);
      setGameState({
        ...DEFAULT_STATE,
        stage: 'playing',
        vitals: initData.vitals,
        messages: [{ role: 'assistant', content: initData.intro, timestamp: Date.now() }],
        learningPoints: initData.learningPoints,
        hiddenDiagnosis: initData.diagnosis,
        caseContext: initData.context,
        visuals: initData.visualCatalog
      });
    } catch (err: any) {
      if (err.message?.includes("entity was not found") || err.message?.includes("API_KEY")) {
        setHasKey(false);
        setError("Your API key is missing or invalid. Please select a valid key.");
      } else {
        setError(err.message);
      }
      setGameState(prev => ({ ...prev, stage: 'upload' }));
    } finally {
      setIsLoading(false);
    }
  };

  const handleUserAction = async (actionText: string) => {
    if (isLoading) return;
    setGameState(prev => ({ ...prev, messages: [...prev.messages, { role: 'user', content: actionText, timestamp: Date.now() }] }));

    setIsLoading(true);
    try {
      const response = await progressSimulation(gameState.caseContext, gameState.messages.map(m => m.content), actionText, gameState.visuals);

      const sysMsg: Message = {
        role: 'assistant',
        content: response.narrative,
        timestamp: Date.now(),
        imageUrl: response.imageIdToDisplay ? gameState.visuals.find(v => v.id === response.imageIdToDisplay)?.data : undefined
      };

      setGameState(prev => ({
        ...prev,
        vitals: response.updatedVitals,
        vitalTrend: response.vitalTrend,
        messages: [...prev.messages, sysMsg],
        labResults: [...(prev.labResults || []), ...(response.labResults || [])],
        diagnosticReports: [...(response.diagnosticReports?.map(r => ({ ...r, timestamp: Date.now() })) || []), ...(prev.diagnosticReports || [])],
        physicalExam: [...(response.physicalExam?.map(e => ({ ...e, timestamp: Date.now() })) || []), ...(prev.physicalExam || [])],
        stage: response.isCaseOver ? 'debrief' : 'playing',
        debriefData: response.debriefData
      }));
    } catch (err: any) {
      if (err.message?.includes("entity was not found")) {
        setHasKey(false);
        setError("Session error: Please re-select your Clinical API Key.");
      } else {
        setError(err.message);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    if (gameState.stage === 'upload' || gameState.stage === 'analyzing') {
      return (
        <div className="flex-1 flex flex-col items-center justify-center p-6 bg-slate-900">
          <div className="max-w-xl w-full bg-slate-800 p-8 rounded-3xl border border-slate-700 shadow-2xl text-center">
            <h2 className="text-3xl font-black mb-2">MediSim <span className="text-emerald-500">ER</span></h2>
            <p className="text-slate-400 mb-8 text-sm uppercase tracking-widest font-bold">Clinical Case Generator</p>

            {gameState.stage === 'analyzing' ? (
              <div className="flex flex-col items-center gap-6 py-10">
                <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin shadow-lg shadow-emerald-500/20"></div>
                <div className="animate-pulse text-emerald-400 font-mono text-sm tracking-widest uppercase">{loadingStep}</div>
              </div>
            ) : (
              <div className="space-y-6">
                {!hasKey ? (
                  <div className="bg-blue-900/20 border border-blue-500/30 p-6 rounded-2xl text-left">
                    <h3 className="text-blue-400 font-bold mb-2 flex items-center gap-2">
                       <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>
                       Clinical Key Required
                    </h3>
                    <p className="text-xs text-slate-400 mb-4 leading-relaxed">
                      To generate cases and let others use their own keys, you must select a Clinical API Key. For high-fidelity cases, use a paid GCP project key.
                    </p>
                    <a 
                      href="https://ai.google.dev/gemini-api/docs/billing" 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="text-[10px] text-blue-400 underline hover:text-blue-300 block mb-4"
                    >
                      View Billing Documentation
                    </a>
                    <button 
                      onClick={handleOpenSelectKey}
                      className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-3 rounded-xl transition-all shadow-lg shadow-blue-900/40 uppercase tracking-widest text-xs"
                    >
                      Select Clinical API Key
                    </button>
                  </div>
                ) : (
                  <>
                    <div className="border-2 border-dashed border-slate-700 rounded-2xl p-8 hover:border-emerald-500 transition-all relative group bg-slate-900/50">
                      <input type="file" multiple onChange={(e) => setSelectedFiles(Array.from(e.target.files || []))} className="absolute inset-0 opacity-0 cursor-pointer z-10" />
                      <div className="flex flex-col items-center gap-2">
                        <svg className="w-10 h-10 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                        </svg>
                        <p className="text-sm font-bold text-slate-300">Drag & Drop CME PDF/Images</p>
                      </div>
                      {selectedFiles.length > 0 && (
                        <div className="mt-4 p-2 bg-emerald-500/10 rounded border border-emerald-500/30">
                          <p className="text-xs text-emerald-400 font-bold">{selectedFiles.length} clinical files staged</p>
                        </div>
                      )}
                    </div>
                    <button 
                      onClick={() => processFiles(selectedFiles)} 
                      disabled={selectedFiles.length === 0}
                      className="w-full bg-emerald-600 hover:bg-emerald-500 py-4 rounded-xl font-black uppercase tracking-widest disabled:opacity-30 transition-all shadow-xl shadow-emerald-900/20"
                    >
                      Generate Simulation
                    </button>
                    <button onClick={handleOpenSelectKey} className="text-[10px] text-slate-600 uppercase font-black tracking-widest hover:text-slate-400">
                      Change API Key
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>
      );
    }

    if (gameState.stage === 'debrief') return <DebriefScreen data={gameState.debriefData!} onRestart={() => setGameState(DEFAULT_STATE)} />;

    return (
      <div className="flex-1 flex flex-col overflow-hidden">
        <VitalsMonitor vitals={gameState.vitals} trend={gameState.vitalTrend} audioEnabled={audioMonitor} />
        <div className="flex-1 flex overflow-hidden">
          <div className="flex-1 flex flex-col relative border-r border-slate-800">
            <ChatInterface messages={gameState.messages} isLoading={isLoading} />
            <Controls onAction={handleUserAction} disabled={isLoading} />
          </div>
          {chartOpen && (
            <div className="w-80 bg-slate-900/60 border-l border-slate-800 overflow-y-auto p-4 space-y-6">
              <h3 className="text-[11px] font-black uppercase tracking-widest text-slate-500 mb-4 border-b border-slate-800 pb-2">Patient Clinical Chart</h3>

              {gameState.physicalExam.length > 0 && (
                <div className="animate-fadeIn">
                  <span className="text-[10px] font-black text-blue-400 uppercase mb-2 block tracking-widest">Physical Exam</span>
                  <div className="space-y-2">
                    {gameState.physicalExam.map((e, i) => (
                      <div key={i} className="p-2 bg-slate-950/80 rounded border border-slate-800">
                        <span className="text-[9px] font-black text-slate-500 uppercase">{e.system}</span>
                        <p className="text-xs text-slate-300 leading-relaxed">{e.finding}</p>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {gameState.diagnosticReports.length > 0 && (
                <div className="animate-fadeIn">
                  <span className="text-[10px] font-black text-emerald-400 uppercase mb-2 block tracking-widest">Radiology & Reports</span>
                  <div className="space-y-2">
                    {gameState.diagnosticReports.map((r, i) => (
                      <div key={i} className="p-2 bg-slate-950/80 rounded border border-slate-800">
                        <span className="text-[9px] font-black text-slate-500 uppercase">{r.title}</span>
                        <p className="text-[10px] text-slate-400 italic leading-relaxed">{r.body}</p>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {gameState.labResults.length > 0 && (
                <div className="animate-fadeIn">
                  <span className="text-[10px] font-black text-yellow-500 uppercase mb-2 block tracking-widest">Lab Results</span>
                  <div className="bg-slate-950/80 rounded border border-slate-800 overflow-hidden divide-y divide-slate-800/50">
                    {gameState.labResults.map((l, i) => (
                      <div key={i} className="flex justify-between items-center px-3 py-1.5 text-[11px]">
                        <span className="text-slate-400">{l.name}</span>
                        <span className={`${l.flag ? 'text-red-500 font-black' : 'text-emerald-400 font-bold'}`}>{l.value} {l.unit}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-slate-200">
      <header className="px-6 py-4 border-b border-slate-900 flex justify-between items-center bg-slate-950 z-50">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-emerald-600 rounded flex items-center justify-center font-black text-white shadow-lg">M</div>
          <h1 className="text-lg font-black tracking-tight">MediSim <span className="text-emerald-500 uppercase text-xs">ER</span></h1>
        </div>
        {gameState.stage === 'playing' && (
          <div className="flex gap-4">
            <button onClick={() => setAudioMonitor(!audioMonitor)} className={`px-3 py-1 rounded text-[10px] font-black uppercase tracking-widest border transition-all ${audioMonitor ? 'bg-emerald-900/30 border-emerald-500 text-emerald-400' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>Monitor</button>
