        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-emerald-600 to-emerald-800 rounded-xl flex items-center justify-center font-black text-white shadow-xl">M</div>
          <div>
             <h1 className="text-xl font-black tracking-tighter leading-none">MediSim <span className="text-emerald-500 text-xs tracking-widest uppercase ml-1">ER</span></h1>
             <p className="text-[9px] text-slate-600 uppercase font-bold tracking-[0.2em] mt-0.5">Clinical Simulator</p>
