        </div>
        {gameState.stage === 'playing' && (
          <div className="flex gap-6">
            <button onClick={() => setAudioMonitor(!audioMonitor)} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all ${audioMonitor ? 'bg-emerald-950/40 border-emerald-500 text-emerald-400 shadow-[0_0_20px_rgba(16,185,129,0.25)]' : 'bg-slate-900 border-slate-800 text-slate-600 hover:text-slate-400'}`}>Monitor</button>
            <button onClick={() => setChartOpen(!chartOpen)} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all ${chartOpen ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-600'}`}>Workspace</button>
          </div>
        )}
      </header>
      {renderContent()}
      {error && <ErrorModal message={error} onDismiss={() => setError(null)} />}
    </div>
  );
};

