import { GoogleGenAI, Type } from "@google/genai";
import { Vitals, SimulationResponse, ExtractedImage } from "../types";

// Helper to create a new AI instance with a specific key
const getAI = (apiKey: string) => new GoogleGenAI({ apiKey });

// Optimized for free-tier usage
const CLINICAL_MODEL = "gemini-3-flash-preview";

function extractJson(text: string): string {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    return text.substring(start, end + 1);
  }
  return text.trim();
}

export interface GeminiFileInput {
  mimeType: string;
  data: string;
}

export const analyzePDFAndStartCase = async (
  apiKey: string,
  files: GeminiFileInput[],
  extractedImages: string[]
): Promise<{ 
  intro: string; 
  vitals: Vitals; 
  context: string; 
  learningPoints: string[]; 
  diagnosis: string;
  visualCatalog: ExtractedImage[];
}> => {
  const ai = getAI(apiKey);

  const systemInstruction = `You are a Clinical Simulation Architect. 
  Your goal is to transform medical documents into a high-fidelity ER simulation.

  RULES:
  1. NO SPOILERS: Never reveal the diagnosis or learning objectives in the intro.
  2. The 'intro' MUST be a bedside scene with character dialogue (Nurse/Patient).
  3. Respond ONLY in valid JSON format.`;

  const prompt = `
    Analyze the attached medical records. Create a complex simulation case.
    Available visual assets: ${extractedImages.length}.

    OUTPUT FORMAT:
    {
      "intro": "Bedside dialogue...",
      "vitals": { "hr": 90, "bpSystolic": 120, "bpDiastolic": 80, "rr": 16, "o2": 98, "temp": 37.0, "rhythm": "Sinus Rhythm" },
      "context": "Secret clinical truth and logic mapping.",
      "learningPoints": ["..."],
      "diagnosis": "The hidden diagnosis",
      "visualCatalog": [ { "id": "0", "label": "Initial EKG" } ]
    }
  `;

  const fileParts = files.map(f => ({
    inlineData: { mimeType: f.mimeType, data: f.data }
  }));

  const response = await ai.models.generateContent({
    model: CLINICAL_MODEL,
    contents: { parts: [...fileParts, { text: prompt }] },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
    },
  });

  const result = JSON.parse(extractJson(response.text));
  const finalVisuals: ExtractedImage[] = (result.visualCatalog || []).map((item: any) => ({
    ...item,
    data: extractedImages[parseInt(item.id)] || ""
  })).filter((v: any) => v.data !== "");

  return { ...result, visualCatalog: finalVisuals };
};

export const progressSimulation = async (
  apiKey: string,
  context: string,
  history: string[],
  userAction: string,
  visuals: ExtractedImage[]
): Promise<SimulationResponse> => {
  const ai = getAI(apiKey);

  const systemInstruction = `You are the Bedside Simulation Engine. 

  STRICT CHARTING RULES:
  1. PHYSICAL EXAM: Only return findings in 'physicalExam' if specifically requested.
  2. RADIOLOGY: If imaging is ordered, return a report in 'diagnosticReports'.
  3. LABS: Return structured values in 'labResults'.
  4. DO NOT reveal the hidden diagnosis in the narrative.
  5. Respond only in JSON.`;

  const visualInventory = (visuals || []).map(v => `ID ${v.id}: ${v.label}`).join(", ");
  const prompt = `CLINICAL TRUTH: ${context}\nHISTORY: ${history.slice(-5).join("\n")}\nUSER ACTION: ${userAction}\nVISUALS: ${visualInventory}`;

  const response = await ai.models.generateContent({
    model: CLINICAL_MODEL,
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
    },
  });

  return JSON.parse(extractJson(response.text));
};

import React, { useState, useEffect, useRef } from 'react';
import { GameState, Message } from './types';
import { analyzePDFAndStartCase, progressSimulation, GeminiFileInput } from './services/geminiService';
import { extractImagesFromPDF } from './services/pdfService';
import VitalsMonitor from './components/VitalsMonitor';
import ChatInterface from './components/ChatInterface';
import Controls from './components/Controls';
import DebriefScreen from './components/DebriefScreen';
import ErrorModal from './components/ErrorModal';
import { startAmbientNoise, stopAmbientNoise } from './services/audioEffectsService';

const SAVE_KEY = 'medisim_er_save_state_v5';
const LOCAL_API_KEY = 'medisim_user_api_key';

const fileToBase64 = (file: File | Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
    reader.onerror = (error) => reject(error);
  });
};

const DEFAULT_STATE: GameState = {
  stage: 'upload',
  vitals: { hr: 0, bpSystolic: 0, bpDiastolic: 0, rr: 0, o2: 0, temp: 0, rhythm: '--' },
  messages: [],
  learningPoints: [],
  hiddenDiagnosis: '',
  caseContext: '',
  visuals: [],
  labResults: [],
  diagnosticReports: [],
  physicalExam: [],
  vitalTrend: 'stable'
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(() => {
    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try { return { ...DEFAULT_STATE, ...JSON.parse(saved) }; } catch (e) { return DEFAULT_STATE; }
    }
    return DEFAULT_STATE;
  });

  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [audioMonitor, setAudioMonitor] = useState(false);
  const [chartOpen, setChartOpen] = useState(true);

  // Explicit User API Key State
  const [userApiKey, setUserApiKey] = useState<string>(() => localStorage.getItem(LOCAL_API_KEY) || '');
  const [isKeyAuthorized, setIsKeyAuthorized] = useState<boolean>(!!localStorage.getItem(LOCAL_API_KEY));

  const handleSetApiKey = () => {
    if (userApiKey.length < 10) {
      setError("Please paste a valid Gemini API Key.");
      return;
    }
    localStorage.setItem(LOCAL_API_KEY, userApiKey);
    setIsKeyAuthorized(true);
  };

  const handleClearKey = () => {
    localStorage.removeItem(LOCAL_API_KEY);
    setUserApiKey('');
    setIsKeyAuthorized(false);
  };

  useEffect(() => {
    if (gameState.stage === 'playing' && audioMonitor) {
       const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
       startAmbientNoise(ctx);
       return () => stopAmbientNoise();
    }
  }, [gameState.stage, audioMonitor]);

  useEffect(() => {
    if (gameState.stage !== 'upload') localStorage.setItem(SAVE_KEY, JSON.stringify(gameState));
  }, [gameState]);

  const processFiles = async (files: File[]) => {
    if (files.length === 0) return;
    if (!isKeyAuthorized) {
      setError("Clinical Terminal Not Initialized. Please provide your API Key.");
      return;
    }

    setIsLoading(true);
    setGameState(prev => ({ ...prev, stage: 'analyzing' }));

    try {
      setLoadingStep('Authenticating Clinical Session...');
      const geminiInputs: GeminiFileInput[] = [];
      const allVisualAssets: string[] = [];

      for (const file of files) {
        setLoadingStep(`Processing ${file.name}...`);
        const base64Data = await fileToBase64(file);
        geminiInputs.push({ mimeType: file.type, data: base64Data });
        if (file.type === 'application/pdf') {
          const extracted = await extractImagesFromPDF(await file.arrayBuffer());
          allVisualAssets.push(...extracted);
        } else {
          allVisualAssets.push(`data:${file.type};base64,${base64Data}`);
        }
      }

      setLoadingStep('Generating Simulation Logic...');
      const initData = await analyzePDFAndStartCase(userApiKey, geminiInputs, allVisualAssets);
      setGameState({
        ...DEFAULT_STATE,
        stage: 'playing',
        vitals: initData.vitals,
        messages: [{ role: 'assistant', content: initData.intro, timestamp: Date.now() }],
        learningPoints: initData.learningPoints,
        hiddenDiagnosis: initData.diagnosis,
        caseContext: initData.context,
        visuals: initData.visualCatalog
      });
    } catch (err: any) {
      setError(err.message || "An error occurred during case initialization.");
      setGameState(prev => ({ ...prev, stage: 'upload' }));
    } finally {
      setIsLoading(false);
    }
  };

  const handleUserAction = async (actionText: string) => {
    if (isLoading) return;
    setGameState(prev => ({ ...prev, messages: [...prev.messages, { role: 'user', content: actionText, timestamp: Date.now() }] }));

    setIsLoading(true);
    try {
      const response = await progressSimulation(userApiKey, gameState.caseContext, gameState.messages.map(m => m.content), actionText, gameState.visuals);

      const sysMsg: Message = {
        role: 'assistant',
        content: response.narrative,
        timestamp: Date.now(),
        imageUrl: response.imageIdToDisplay ? gameState.visuals.find(v => v.id === response.imageIdToDisplay)?.data : undefined
      };

      setGameState(prev => ({
        ...prev,
        vitals: response.updatedVitals,
        vitalTrend: response.vitalTrend,
        messages: [...prev.messages, sysMsg],
        labResults: [...(prev.labResults || []), ...(response.labResults || [])],
        diagnosticReports: [...(response.diagnosticReports?.map(r => ({ ...r, timestamp: Date.now() })) || []), ...(prev.diagnosticReports || [])],
        physicalExam: [...(response.physicalExam?.map(e => ({ ...e, timestamp: Date.now() })) || []), ...(prev.physicalExam || [])],
        stage: response.isCaseOver ? 'debrief' : 'playing',
        debriefData: response.debriefData
      }));
    } catch (err: any) {
      setError(err.message || "Connection to clinical engine failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    if (gameState.stage === 'upload' || gameState.stage === 'analyzing') {
      return (
        <div className="flex-1 flex flex-col items-center justify-center p-6 bg-slate-950">
          <div className="max-w-xl w-full bg-slate-900/40 p-12 rounded-[3.5rem] border border-slate-800 shadow-[0_40px_100px_rgba(0,0,0,0.8)] text-center relative overflow-hidden backdrop-blur-sm">
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-emerald-600 via-blue-500 to-emerald-600 animate-pulse"></div>

            <h2 className="text-5xl font-black mb-1 text-white tracking-tighter">MediSim <span className="text-emerald-500">ER</span></h2>
            <p className="text-slate-600 mb-14 text-[11px] uppercase tracking-[0.6em] font-black">Clinical Simulation Terminal</p>

            {gameState.stage === 'analyzing' ? (
              <div className="flex flex-col items-center gap-12 py-12">
                <div className="relative w-32 h-32">
                  <div className="absolute inset-0 border-8 border-emerald-500/5 rounded-full"></div>
                  <div className="absolute inset-0 border-t-8 border-emerald-500 rounded-full animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center">
                    <span className="text-xs font-black text-emerald-500 tracking-widest animate-pulse">DNA</span>
                  </div>
                </div>
                <div className="animate-pulse text-emerald-400 font-mono text-base tracking-[0.2em] uppercase">{loadingStep}</div>
              </div>
            ) : (
              <div className="space-y-12">
                {!isKeyAuthorized ? (
                  <div className="bg-slate-950/80 border border-slate-800 p-10 rounded-[2.5rem] text-left">
                    <div className="flex items-center gap-5 mb-8">
                      <div className="w-14 h-14 rounded-2xl bg-emerald-600/10 flex items-center justify-center text-emerald-500 border border-emerald-500/10">
                        <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 24 24"><path d="M12.65 10C11.83 7.67 9.61 6 7 6c-3.31 0-6 2.69-6 6s2.69 6 6 6c2.61 0 4.83-1.67 5.65-4H17v4h4v-4h2v-4H12.65zM7 14c-1.1 0-2-.9-2-2s.9-2 2-2 2 .9 2 2-.9 2-2 2z"/></svg>
                      </div>
                      <div>
                        <h3 className="text-white font-black text-xl uppercase tracking-tight">Clinical Access</h3>
                        <p className="text-[10px] text-slate-500 uppercase font-black tracking-widest mt-1">Paste your private API Key</p>
                      </div>
                    </div>

                    <div className="space-y-6">
                      <div className="relative">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500 font-mono text-xl opacity-40">&gt;</div>
                        <input 
                          type="password"
                          value={userApiKey}
                          onChange={(e) => setUserApiKey(e.target.value)}
                          placeholder="Paste API Key here..."
                          className="w-full bg-slate-900 border border-slate-800 rounded-2xl py-5 pl-12 pr-6 text-emerald-400 font-mono placeholder:text-slate-700 focus:outline-none focus:border-emerald-500/50 transition-all shadow-inner"
                        />
                      </div>
                      <p className="text-[10px] text-slate-600 leading-relaxed font-bold uppercase tracking-widest px-1">
                        Your key is stored locally in this browser. We never share your quota with others.
                      </p>
                      <button 
                        onClick={handleSetApiKey}
                        className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-black py-6 rounded-3xl transition-all shadow-[0_20px_40px_rgba(16,185,129,0.3)] uppercase tracking-[0.3em] text-sm active:scale-[0.97]"
                      >
                        Initialize Terminal
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="border-4 border-dashed border-slate-800 rounded-[3.5rem] p-16 hover:border-emerald-500/40 transition-all relative group bg-slate-950/50 cursor-pointer shadow-inner overflow-hidden">
                      <div className="absolute top-2 right-6">
                        <button onClick={handleClearKey} className="text-[9px] font-black text-slate-700 hover:text-red-500 uppercase tracking-widest transition-colors">Disconnect Key</button>
                      </div>
                      <input type="file" multiple onChange={(e) => setSelectedFiles(Array.from(e.target.files || []))} className="absolute inset-0 opacity-0 cursor-pointer z-10" />
                      <div className="flex flex-col items-center gap-8">
                        <div className="w-24 h-24 rounded-[2.5rem] bg-slate-900 flex items-center justify-center text-slate-700 group-hover:text-emerald-500 transition-all shadow-2xl group-hover:shadow-emerald-500/10 border border-slate-800 group-hover:border-emerald-500/30">
                          <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                          </svg>
                        </div>
                        <div>
                          <p className="text-2xl font-black text-white">Load Clinical Record</p>
                          <p className="text-xs text-slate-600 uppercase font-black tracking-[0.4em] mt-3">Upload PDF, PNG, or JPEG</p>
                        </div>
                      </div>
                      {selectedFiles.length > 0 && (
                        <div className="mt-10 p-5 bg-emerald-500/5 rounded-2xl border border-emerald-500/20 animate-fadeIn">
                          <p className="text-[10px] text-emerald-500 font-black tracking-[0.4em] uppercase">{selectedFiles.length} Medical Records Staged</p>
                        </div>
                      )}
                    </div>
                    <div className="flex flex-col gap-6">
                      <button 
